@app.route('/enable-mfa', methods=['POST'])
@login_required
@mfa_verified_required
def enable_mfa():
    user_id = session['user_id']
    user = users_db[user_id]

    if user.get('mfa_enabled'):
        return jsonify({'error': 'MFA is already enabled'}), 400

    # Generate a new TOTP secret
    secret = pyotp.random_base32()
    totp = pyotp.TOTP(secret)
    provisioning_uri = totp.provisioning_uri(
        name=user['email'],
        issuer_name='MFA Management System'
    )

    # Generate QR code as base64
    qr = qrcode.QRCode(version=1, box_size=10, border=5)
    qr.add_data(provisioning_uri)
    qr.make(fit=True)
    img = qr.make_image(fill_color="black", back_color="white")
    buffer = io.BytesIO()
    img.save(buffer, format='PNG')
    qr_base64 = base64.b64encode(buffer.getvalue()).decode('utf-8')

    # Store secret temporarily (not yet confirmed)
    user['mfa_secret'] = secret
    user['mfa_verified_setup'] = False
    user['updated_at'] = datetime.utcnow().isoformat()

    return jsonify({
        'message': 'Scan the QR code with your authenticator app, then confirm with a TOTP code.',
        'secret': secret,
        'provisioning_uri': provisioning_uri,
        'qr_code_base64': qr_base64
    }), 200


@app.route('/confirm-mfa', methods=['POST'])
@login_required
@mfa_verified_required
def confirm_mfa():
    user_id = session['user_id']
    user = users_db[user_id]

    if user.get('mfa_enabled'):
        return jsonify({'error': 'MFA is already enabled'}), 400

    if not user.get('mfa_secret'):
        return jsonify({'error': 'Please initiate MFA setup first via /enable-mfa'}), 400

    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body is required'}), 400

    totp_code = data.get('totp_code', '').strip()
    if not totp_code:
        return jsonify({'error': 'TOTP code is required to confirm MFA setup'}), 400

    totp = pyotp.TOTP(user['mfa_secret'])
    if totp.verify(totp_code, valid_window=1):
        user['mfa_enabled'] = True
        user['mfa_verified_setup'] = True
        user['updated_at'] = datetime.utcnow().isoformat()
        return jsonify({'message': 'MFA has been enabled successfully'}), 200
    else:
        return jsonify({'error': 'Invalid TOTP code. Please try again.'}), 400


@app.route('/disable-mfa', methods=['POST'])
@login_required
@mfa_verified_required
def disable_mfa():
    user_id = session['user_id']
    user = users_db[user_id]

    if not user.get('mfa_enabled'):
        return jsonify({'error': 'MFA is not enabled'}), 400

    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body is required'}), 400

    # Require password confirmation to disable MFA
    password = data.get('password', '')
    if not password:
        return jsonify({'error': 'Password confirmation is required to disable MFA'}), 400

    if not check_password_hash(user['password_hash'], password):
        return jsonify({'error': 'Invalid password'}), 401

    # Require current TOTP code
    totp_code = data.get('totp_code', '').strip()
    if not totp_code:
        return jsonify({'error': 'Current TOTP code is required'}), 400

    totp = pyotp.TOTP(user['mfa_secret'])
    if not totp.verify(totp_code, valid_window=1):
        return jsonify({'error': 'Invalid TOTP code'}), 401

    user['mfa_enabled'] = False
    user['mfa_secret'] = None
    user['mfa_verified_setup'] = False
    user['updated_at'] = datetime.utcnow().isoformat()

    return jsonify({'message': 'MFA has been disabled successfully'}), 200


@app.route('/reset-mfa', methods=['POST'])
def reset_mfa():
    """Request MFA reset. Sends a reset link to the registered email."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body is required'}), 400

    email = data.get('email', '').strip().lower()
    if not email:
        return jsonify({'error': 'Email is required'}), 400

    # Find user by email
    target_user = None
    for uid, user in users_db.items():
        if user['email'] == email:
            target_user = user
            break

    # Always return success to prevent email enumeration
    success_message = (
        'If an account with that email exists and has MFA enabled, '
        'a reset link has been sent to the email address.'
    )

    if not target_user:
        return jsonify({'message': success_message}), 200

    if not target_user.get('mfa_enabled'):
        return jsonify({'message': success_message}), 200

    # Rate limiting: check if a token was recently issued
    for token, token_data in mfa_reset_tokens.items():
        if (token_data['user_id'] == target_user['user_id'] and
                not token_data.get('used') and
                datetime.utcnow() < datetime.fromisoformat(token_data['expires_at'])):
            # Check cooldown (5 minutes between requests)
            created = datetime.fromisoformat(token_data['created_at'])
            if datetime.utcnow() - created < timedelta(minutes=5):
                return jsonify({
                    'message': success_message,
                    'note': 'Please wait before requesting another reset link.'
                }), 200

    # Generate secure reset token
    reset_token = secrets.token_urlsafe(48)
    expiry = datetime.utcnow() + timedelta(hours=1)

    mfa_reset_tokens[reset_token] = {
        'user_id': target_user['user_id'],
        'email': email,
        'created_at': datetime.utcnow().isoformat(),
        'expires_at': expiry.isoformat(),
        'used': False
    }

    # Build reset link
    reset_link = url_for('confirm_reset_mfa', token=reset_token, _external=True)

    # Send email
    email_body = (
        f"Hello,\n\n"
        f"We received a request to reset MFA for your account ({email}).\n\n"
        f"Click the link below to disable MFA and regain access to your account:\n\n"
        f"{reset_link}\n\n"
        f"This link will expire in 1 hour.\n\n"
        f"If you did not request this, please ignore this email and ensure your account is secure.\n\n"
        f"- MFA Management System"
    )

    send_email(email, 'MFA Reset Request', email_body)

    return jsonify({'message': success_message}), 200


